// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertInstanceOf;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Set;

import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Projection;
import org.eclipse.rdf4j.query.algebra.ProjectionElem;
import org.eclipse.rdf4j.query.algebra.ProjectionElemList;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.junit.jupiter.api.Test;

class CascadesPlannerReservedFallbackTest {

	@Test
	void autoZeroExploratoryWorkStillReturnsReservedOriginalTopologyWinner() {
		Projection input = projectionOverStatementPattern();

		CascadesPlan plan = plannerWithLimits(zeroExploratoryLimits()).optimize(input,
				goal(OptimizationGoal.SearchMode.AUTO));

		TupleExpr selected = plan.tupleExpr()
				.orElseThrow(
						() -> new AssertionError(
								"AUTO must reserve one legal executable plan outside exploratory limits"));
		Projection selectedProjection = assertInstanceOf(Projection.class, selected);
		assertInstanceOf(StatementPattern.class, selectedProjection.getArg());
		assertEquals(OptimizationCompleteness.BUDGET_EXHAUSTED, plan.completeness());
		assertEquals(Set.of(OptimizationLimitCause.RULE_WORK), plan.searchStatus().limitCauses());
		assertEquals(0L, plan.searchStatus().counters().ruleWork());
		assertFalse(plan.pendingTasks().isEmpty(), "The unexecuted registered rule must remain visible as deferred");
		assertTrue(plan.approximate());
	}

	@Test
	void autoReservationDoesNotDependOnExploratoryImplementationGates() {
		Filter input = new Filter(statementPattern(), new Var("condition"));
		RuleRegistry rules = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule(tupleExpr -> !(tupleExpr instanceof Filter)))
				.build();

		CascadesPlan plan = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), rules,
				CascadesTelemetry.NO_OP, zeroExploratoryLimits()).optimize(input,
						goal(OptimizationGoal.SearchMode.AUTO));

		TupleExpr selected = plan.tupleExpr()
				.orElseThrow(
						() -> new AssertionError("The reserved topology must bypass exploratory implementation gates"));
		Filter selectedFilter = assertInstanceOf(Filter.class, selected);
		assertInstanceOf(StatementPattern.class, selectedFilter.getArg());
		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness());
		assertTrue(plan.searchStatus().limitCauses().isEmpty());
		assertEquals(0L, plan.searchStatus().counters().ruleWork());
		assertTrue(plan.pendingTasks().isEmpty());
	}

	@Test
	void autoReservationRetainsUnsupportedRootOccurrenceIdentity() {
		QueryRoot input = new QueryRoot(projectionOverStatementPattern());

		CascadesPlan plan = plannerWithLimits(zeroExploratoryLimits()).optimize(input,
				goal(OptimizationGoal.SearchMode.AUTO));

		TupleExpr selected = plan.tupleExpr()
				.orElseThrow(() -> new AssertionError(
						"The reserved topology must retain the imported opaque root occurrence identity"));
		QueryRoot selectedRoot = assertInstanceOf(QueryRoot.class, selected);
		Projection selectedProjection = assertInstanceOf(Projection.class, selectedRoot.getArg());
		assertInstanceOf(StatementPattern.class, selectedProjection.getArg());
		assertEquals(OptimizationCompleteness.BUDGET_EXHAUSTED, plan.completeness());
		assertEquals(Set.of(OptimizationLimitCause.RULE_WORK), plan.searchStatus().limitCauses());
		assertEquals(0L, plan.searchStatus().counters().ruleWork());
		assertFalse(plan.pendingTasks().isEmpty());
		assertTrue(plan.approximate());
	}

	@Test
	void exactZeroExploratoryWorkReportsTransactionalResourceLimit() {
		Projection input = projectionOverStatementPattern();

		CascadesPlan plan = plannerWithLimits(zeroExploratoryLimits()).optimize(input,
				goal(OptimizationGoal.SearchMode.EXACT));

		assertEquals(OptimizationCompleteness.RESOURCE_LIMIT_EXCEEDED, plan.completeness());
		assertNotEquals(OptimizationCompleteness.COMPLETE, plan.completeness());
		assertEquals(Set.of(OptimizationLimitCause.RULE_WORK), plan.searchStatus().limitCauses());
		assertEquals(0L, plan.searchStatus().counters().ruleWork());
		assertFalse(plan.pendingTasks().isEmpty(), "incomplete EXACT must expose every deferred task");
		assertTrue(plan.approximate());
	}

	private static CascadesPlanner plannerWithLimits(SearchLimits limits) {
		RuleRegistry rules = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();
		return new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), rules,
				CascadesTelemetry.NO_OP, limits);
	}

	private static OptimizationGoal goal(OptimizationGoal.SearchMode mode) {
		return new OptimizationGoal(PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS,
				OptimizationGoal.CostPolicy.EXACT, CostVector.INFINITE, Set.of(), mode, Long.MAX_VALUE, 4_096);
	}

	private static SearchLimits zeroExploratoryLimits() {
		return new SearchLimits(0L, Long.MAX_VALUE, Long.MAX_VALUE, Long.MAX_VALUE, Long.MAX_VALUE,
				Long.MAX_VALUE, Long.MAX_VALUE);
	}

	private static Projection projectionOverStatementPattern() {
		ProjectionElemList elements = new ProjectionElemList();
		elements.addElement(new ProjectionElem("subject"));
		return new Projection(statementPattern(), elements, false);
	}

	private static StatementPattern statementPattern() {
		return new StatementPattern(new Var("subject"), new Var("predicate"), new Var("object"));
	}
}
